import"./hoisted.BvU8MTC3.js";async function c(){try{const s=await fetch("/api/oscp-stats");if(!s.ok)return;const t=await s.json(),n=document.getElementById("stat-issues"),e=document.getElementById("stat-commits"),o=document.getElementById("stat-angular");if(n&&(n.textContent=`${t.openIssues} unresolved`),e&&(e.textContent=`${t.commitsLast6Months} commit${t.commitsLast6Months!==1?"s":""}`),o){const a=t.angularVersion.split(".").slice(0,2).join(".");o.innerHTML=`${a} <span style="font-size: 0.65em; color: #94a3b8;">(current: ${t.currentAngularVersion})</span>`}}catch{}}c();
